@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
    </div>
}
else
{
    <!-- Stats bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>Total</strong><span>@_allTasks.Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>To Do</strong><span>@GetColumnTasks("To Do").Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>In Progress</strong><span>@GetColumnTasks("In Progress").Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>Done</strong><span>@GetColumnTasks("Done").Count</span></div></div>
        <div class="col"><div class="card text-center p-2 text-danger"><strong>Overdue</strong><span>@_allTasks.Count(t => t.DueDate < DateTime.Today)</span></div></div>
    </div>

    <!-- Search bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban columns -->
    <div class="row g-3">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height:60vh;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (GetColumnIndex(column) > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(column) - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (GetColumnIndex(column) < _columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(column) + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (_addingToColumn == column)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2 d-flex flex-column gap-2">
                                    <input type="text" class="form-control form-control-sm" placeholder="Title"
                                           @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                                           @bind="_newAssignee" />
                                    <select class="form-select form-select-sm" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm"
                                           @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm" @onclick="SaveNewTaskAsync">Save</button>
                                        <button class="btn btn-secondary btn-sm" @onclick="CancelAddTask">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-outline-primary btn-sm w-100"
                                @onclick="() => StartAddTask(column)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // New-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchText) ||
                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private int GetColumnIndex(string column) => Array.IndexOf(_columns, column);

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = _allTasks.First(t => t.Id == taskId);
            _allTasks[_allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private void StartAddTask(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAddTask() => _addingToColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null)
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync returns the task; if the status doesn't match the column, move it
            if (created.Status != _addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn);
                created = created with { Status = _addingToColumn };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

