                        {
                            <div class="card border-primary">
                                <div class="card-body p-2 d-flex flex-column gap-2">
                                    <input type="text" class="form-control form-control-sm" placeholder="Title"
                                           @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                                           @bind="_newAssignee" />
                                    <select class="form-select form-select-sm" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm"
                                           @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm" @onclick="SaveNewTaskAsync">Save</button>
                                        <button class="btn btn-secondary btn-sm" @onclick="CancelAddTask">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-outline-primary btn-sm w-100"
                                @onclick="() => StartAddTask(column)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

